SELECT 
FROM videos
WHERE is_public = TRUE AND deleted_at IS NULL AND status <> 'failed'

    AND user_id = #{userId}

ORDER BY created_at DESC, id DESC
LIMIT #{size} OFFSET #{offset}

SELECT 
FROM videos
WHERE is_public = TRUE AND deleted_at IS NULL AND status <> 'failed'
  AND gym_id = #{gymId}
ORDER BY created_at DESC, id DESC
LIMIT #{size} OFFSET #{offset}
